export function getCountryDialCode(isoCode: string): string {
  return COUNTRY_DIAL_CODES[isoCode.toUpperCase()] ?? '';
}

export function resolveIsoForDialCode(dialCode: string, preferredIso?: string): string {
  const normalized = normalizeDialCode(dialCode);
  if (!normalized) return '';
  const isos = DIAL_CODE_TO_ISOS[normalized] ?? [];
  if (isos.length === 0) return '';
  const preferred = preferredIso?.trim().toUpperCase();
  if (preferred && isos.includes(preferred)) return preferred;
  if (normalized === '+1') {
    if (isos.includes('US')) return 'US';
    if (isos.includes('CA')) return 'CA';
  }
  if (normalized === '+44' && isos.includes('GB')) return 'GB';
  if (normalized === '+61' && isos.includes('AU')) return 'AU';
  return isos[0] ?? '';
}

export function normalizeDialCode(value: string): string {
  const trimmed = value.trim();
  if (!trimmed) return '';
  const digits = trimmed.replace(/[^\d+]/g, '');
  if (!digits) return '';
  const withPlus = digits.startsWith('+') ? digits : `+${digits}`;
  return withPlus.replace(/(?!^)\+/g, '');
}

export function getAllDialCodeEntries(): { iso: string; dial: string; name?: string }[] {
  return Object.entries(COUNTRY_DIAL_CODES).map(([iso, dial]) => ({ iso, dial }));
}

/** Fallback country rows for dial-code pickers when reference API data is unavailable. */
export function dialCodeCountriesFallback(): Country[] {
  const displayNames = new Intl.DisplayNames(['en'], { type: 'region' });

  return Object.keys(COUNTRY_DIAL_CODES)
    .map((iso_code) => ({
      iso_code,
      name: displayNames.of(iso_code) ?? iso_code,
      default_timezone_id: null,
    }))
    .sort((a, b) => a.name.localeCompare(b.name));
}
